              },
              { label: '--zine-shadow-red', shadow: 'var(--zine-shadow-red, 4px 4px 0 #d42b2b)' },
              {
                label: '--zine-shadow-blue',
                shadow: 'var(--zine-shadow-blue, 4px 4px 0 #1a3c8f)',
