          <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
            {['--radius-sm', '--radius-md', '--radius-lg', '--radius-pill'].map((label) => (
              <div key={label} style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
