import type { Meta, StoryObj } from '@storybook/nextjs-vite';

const meta = {
  title: 'Design System/Tokens',
  parameters: {
    // 'paper' = #ede5c8 matches the actual light-mode --ds-page value.
    // Toggle to 'dark' (#11111b) to preview dark-mode rendering.
    backgrounds: { default: 'paper' },
    docs: {
      description: {
        component:
          'Garden Design System — NEU-BRUTALISM × PUNK ZINE palette. ' +
          'All values are CSS custom properties (`--zine-*`, `--ds-*`) sourced from `packages/components/src/styles/tokens.css` and cascade into Lit shadow DOMs automatically. ' +
          'Use the theme toggle (☀/☽) or the Storybook Themes addon to preview dark mode.',
      },
    },
  },
} satisfies Meta;

export default meta;
type Story = StoryObj<typeof meta>;

/* ── Shared mini-components ──────────────────────────────────────────────── */

/** Paint-swatch block — shows raw hex so the value is legible at a glance */
const Swatch = ({
  color,
  label,
  variable,
  dark = false,
}: {
  color: string;
  label: string;
  variable: string;
  dark?: boolean;
}) => (
  <div
    style={{
      border: '3px solid var(--zine-ink, #0e0c07)',
      borderRight: '4px solid var(--zine-ink, #0e0c07)',
      borderBottom: '4px solid var(--zine-ink, #0e0c07)',
      display: 'inline-flex',
      flexDirection: 'column',
    }}
  >
    <div style={{ width: 52, height: 44, background: color }} />
    <div
      style={{
        fontFamily: "'Cutive Mono', monospace",
        fontSize: 9,
        padding: '3px 5px',
        background: dark ? '#0e0c07' : 'var(--zine-paper, #f2edd7)',
        color: dark ? '#f2edd7' : 'var(--zine-ink, #0e0c07)',
        borderTop: '2px solid var(--zine-ink, #0e0c07)',
        letterSpacing: '0.04em',
        lineHeight: 1.5,
      }}
    >
      {variable}
      <br />
      {label}
    </div>
  </div>
);

const TokenRow = ({ name, value }: { name: string; value: string }) => (
  <div
    style={{
      fontFamily: "'Cutive Mono', monospace",
      fontSize: 11,
      display: 'flex',
      justifyContent: 'space-between',
      padding: '4px 6px',
      border: '1px solid var(--ds-border, rgba(14, 12, 7, 0.15))',
      background: 'var(--ds-toggle-bg, rgba(255,255,255,0.25))',
    }}
  >
    <span style={{ color: 'var(--zine-ink-faded, #2c2820)' }}>{name}</span>
    <span style={{ color: 'var(--zine-red, #d42b2b)', fontWeight: 'bold' }}>{value}</span>
  </div>
);

const SectionLabel = ({ children }: { children: string }) => (
  <div
    style={{
      fontFamily: "'Bebas Neue', sans-serif",
      fontSize: 22,
      color: 'var(--zine-ink, #0e0c07)',
      letterSpacing: '0.08em',
      marginBottom: '1.25rem',
      display: 'flex',
      alignItems: 'center',
      gap: 10,
    }}
  >
    <span style={{ color: 'var(--zine-red, #d42b2b)' }}>//</span>
    {children}
    <div style={{ flex: 1, height: 3, background: 'var(--zine-ink, #0e0c07)', marginLeft: 8 }} />
  </div>
);

const Sheet = ({
  children,
  pinColor = 'var(--zine-red, #d42b2b)',
  pinBorder = 'var(--zine-red-dark, #8a0000)',
}: {
  children: React.ReactNode;
  pinColor?: string;
  pinBorder?: string;
}) => (
  <div
    style={{
      background: 'var(--zine-paper, #f2edd7)',
      border: 'var(--zine-border, 3px solid #0e0c07)',
      borderRight: '5px solid var(--zine-ink, #0e0c07)',
      borderBottom: '5px solid var(--zine-ink, #0e0c07)',
      padding: '1.5rem',
      position: 'relative',
      marginTop: '2.5rem',
      boxShadow: 'var(--zine-shadow-lg, 6px 6px 0 #0e0c07)',
    }}
  >
    <div
      style={{
        position: 'absolute',
        top: -10,
        left: 24,
        width: 18,
        height: 18,
        background: pinColor,
        border: `2px solid ${pinBorder}`,
        borderRadius: '50%',
        boxShadow: '0 2px 4px rgba(0,0,0,0.4)',
      }}
    />
    {children}
  </div>
);

/* ── Page wrapper — uses CSS vars to respond to theme toggle ─────────────── */
const PageWrap = ({ children }: { children: React.ReactNode }) => (
  <div
    style={{
      padding: '2rem 1.5rem',
      background: 'var(--ds-page, #ede5c8)',
      minHeight: '100vh',
    }}
  >
    {children}
  </div>
);

